#!/usr/bin/env python3
"""flag_debt_scan.py — find flag debt in the source tree."""
import ast, re, sys, yaml
from datetime import date
from pathlib import Path

REGISTRY_PATH = Path("config/flags.yml")
SRC_DIR       = Path("src")

def load_registry() -> dict:
    with open(REGISTRY_PATH) as f:
        return yaml.safe_load(f)["flags"]

class FlagVisitor(ast.NodeVisitor):
    """Count is_enabled() calls and detect nested flag checks."""
    def __init__(self):
        self.calls: list[tuple[str, int]] = []   # (flag_name, line)
        self.nesting_depth = 0
        self.max_nesting = 0

    def visit_If(self, node):
        self.nesting_depth += 1
        self.max_nesting = max(self.max_nesting, self.nesting_depth)
        self.generic_visit(node)
        self.nesting_depth -= 1

    def visit_Call(self, node):
        if (isinstance(node.func, ast.Attribute) and node.func.attr == "is_enabled"
                or isinstance(node.func, ast.Name) and node.func.id == "is_enabled"):
            if node.args and isinstance(node.args[0], ast.Constant):
                self.calls.append((node.args[0].value, node.lineno))
        self.generic_visit(node)

def scan_source(registry: dict) -> list[dict]:
    issues = []
    today = date.today()

    # 1. Expired flags in registry
    for name, cfg in registry.items():
        if cfg.get("state") == "retired":
            continue
        if "expires_after" in cfg:
            exp = date.fromisoformat(str(cfg["expires_after"]))
            if exp < today:
                days_over = (today - exp).days
                issues.append({
                    "type": "expired",
                    "flag": name,
                    "detail": f"{days_over}d past expires_after ({cfg['expires_after']})",
                    "owner": cfg.get("owner", "unknown"),
                })

    # 2. full_on flags that haven't been retired
    for name, cfg in registry.items():
        if cfg.get("state") == "full_on":
            issues.append({
                "type": "stale_full_on",
                "flag": name,
                "detail": "State is full_on — should be retired or code hardened",
                "owner": cfg.get("owner", "unknown"),
            })

    # 3. Deeply nested flag checks in source
    for py_file in SRC_DIR.rglob("*.py"):
        try:
            tree = ast.parse(py_file.read_text())
        except SyntaxError:
            continue
        visitor = FlagVisitor()
        visitor.visit(tree)
        if visitor.max_nesting >= 3 and visitor.calls:
            issues.append({
                "type": "nested_flags",
                "flag": "multiple",
                "detail": f"{py_file}: nesting depth {visitor.max_nesting} with flag checks",
                "owner": "engineering",
            })

    return issues

if __name__ == "__main__":
    registry = load_registry()
    issues = scan_source(registry)
    if issues:
        print(f"Flag debt scan: {len(issues)} issue(s) found")
        for iss in issues:
            print(f"  [{iss['type']}] {iss['flag']}: {iss['detail']} (owner: {iss['owner']})")
        sys.exit(1)
    print("Flag debt scan: clean")

# BEFORE cleanup — flag guard present
from src.flags import is_enabled
from src.cache import get_cached_response, cache_response

def generate(prompt: str) -> str:
    if is_enabled("cache_streaming"):
        cached = get_cached_response(prompt)
        if cached:
            return cached

    result = _call_model(prompt)

    if is_enabled("cache_streaming"):
        cache_response(prompt, result)

    return result

#!/usr/bin/env python3
"""record_flag_metrics.py — append flag inventory snapshot to trend file."""
import json, yaml, os
from datetime import date
from pathlib import Path

REGISTRY_PATH = Path("config/flags.yml")
TREND_FILE    = Path("metrics/flag-inventory.json")

def snapshot() -> dict:
    with open(REGISTRY_PATH) as f:
        flags = yaml.safe_load(f)["flags"]
    today = date.today()
    counts = {"registered": 0, "default_off": 0, "canary": 0, "full_on": 0, "retired": 0}
    expired = 0
    for name, cfg in flags.items():
        state = cfg.get("state", "registered")
        counts[state] = counts.get(state, 0) + 1
        if "expires_after" in cfg and cfg["state"] != "retired":
            if date.fromisoformat(str(cfg["expires_after"])) < today:
                expired += 1
    return {
        "date": str(today),
        "total_active": sum(v for k, v in counts.items() if k != "retired"),
        "full_on_unretired": counts["full_on"],
        "expired": expired,
        "by_state": counts,
    }

def append(snap: dict) -> None:
    try:
        with open(TREND_FILE) as f:
            trend = json.load(f)
    except FileNotFoundError:
        trend = []
    trend = [t for t in trend if t["date"] != snap["date"]]
    trend.append(snap)
    TREND_FILE.parent.mkdir(exist_ok=True)
    with open(TREND_FILE, "w") as f:
        json.dump(trend, f, indent=2)

if __name__ == "__main__":
    s = snapshot()
    append(s)
    print(json.dumps(s, indent=2))
    # Example healthy output:
    # {"date": "2025-08-12", "total_active": 6, "full_on_unretired": 1, "expired": 0}
